import{_ as s}from"./chunks/model-families.C8D2g9ev.js";import{b as l,I as a,g as i,j as n}from"./chunks/framework.DUo3J_Qe.js";const o="/geo-ml/learning/concepts/machine-learning.svg",f=JSON.parse('{"title":"Concepts fondamentaux","description":"","frontmatter":{},"headers":[],"relativePath":"fr/learning/concepts/fundamentals.md","filePath":"fr/learning/concepts/fundamentals.md"}'),t={name:"fr/learning/concepts/fundamentals.md"};function r(d,e,m,u,c,p){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="concepts-fondamentaux" tabindex="-1">Concepts fondamentaux <a class="header-anchor" href="#concepts-fondamentaux" aria-label="Permalink to &quot;Concepts fondamentaux&quot;">​</a></h1><p>Quand on parle d’intelligence artificielle, on met souvent tout dans le même sac.<br> En réalité, il existe <strong>plusieurs grandes familles de modèles</strong>, qui se distinguent par <strong>ce qu’ils font</strong> et <strong>comment ils apprennent</strong>.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Les modèles de génération (texte, images, audio…) ne représentent qu’une partie de l’écosystème.</p></div><h2 id="le-parcours-classique-en-data-science" tabindex="-1">Le parcours classique en data science <a class="header-anchor" href="#le-parcours-classique-en-data-science" aria-label="Permalink to &quot;Le parcours classique en data science&quot;">​</a></h2><p><img src="'+o+'" alt="Machine Learning"></p><ol><li>Le point de départ est toujours le <strong>monde réel</strong></li><li>Un <strong>problème</strong> ou une <strong>question</strong> se pose, par exemple : <ul><li>Comment prédire une valeur future ?</li><li>Comment expliquer l’influence d’une variable sur une autre ?</li></ul></li><li>Les données sont : <ul><li>collectées</li><li>stockées</li><li>nettoyées</li><li>explorées (EDA)</li></ul></li><li>Enfin, des <strong>modèles de machine learning</strong> sont utilisés pour : <ul><li>faire des prédictions</li><li>découvrir des structures cachées dans les données</li></ul></li></ol><h2 id="les-grandes-familles-de-modeles" tabindex="-1">Les grandes familles de modèles <a class="header-anchor" href="#les-grandes-familles-de-modeles" aria-label="Permalink to &quot;Les grandes familles de modèles&quot;">​</a></h2><p>Chaque famille répond à une <strong>question fondamentale différente</strong>.</p><p><img src="'+s+'" alt="familles de modèles"></p><h3 id="modeles-de-classification" tabindex="-1">Modèles de classification <a class="header-anchor" href="#modeles-de-classification" aria-label="Permalink to &quot;Modèles de classification&quot;">​</a></h3><p>👉 <em>« C’est quoi ? »</em></p><p>Décider dans quelle <strong>catégorie</strong> appartient une donnée.</p><details class="details custom-block"><summary><strong>Exemples</strong></summary><ul><li>Email → spam / non spam</li><li>Image → chat / chien</li><li>Transaction → fraude / normale</li></ul></details><h3 id="modeles-de-regression" tabindex="-1">Modèles de régression <a class="header-anchor" href="#modeles-de-regression" aria-label="Permalink to &quot;Modèles de régression&quot;">​</a></h3><p>👉 <em>« Combien ? »</em></p><p>Prédire une <strong>valeur numérique continue</strong>.</p><details class="details custom-block"><summary><strong>Exemples</strong></summary><ul><li>Prix d’un appartement</li><li>Temps de livraison</li><li>Consommation électrique</li></ul></details><h3 id="modeles-de-clustering-non-supervises" tabindex="-1">Modèles de clustering (non supervisés) <a class="header-anchor" href="#modeles-de-clustering-non-supervises" aria-label="Permalink to &quot;Modèles de clustering (non supervisés)&quot;">​</a></h3><p>👉 <em>« Qui ressemble à qui ? »</em></p><p>Regrouper les données <strong>sans labels</strong>.</p><details class="details custom-block"><summary><strong>Exemples</strong></summary><ul><li>Segmentation client</li><li>Regroupement d’articles</li><li>Analyse de comportements</li></ul></details><h3 id="modeles-de-detection-d-anomalies" tabindex="-1">Modèles de détection d’anomalies <a class="header-anchor" href="#modeles-de-detection-d-anomalies" aria-label="Permalink to &quot;Modèles de détection d’anomalies&quot;">​</a></h3><p>👉 <em>« Qu’est-ce qui est anormal ? »</em></p><p>Identifier les comportements atypiques.</p><details class="details custom-block"><summary><strong>Exemples</strong></summary><ul><li>Fraude bancaire</li><li>Pannes industrielles</li><li>Intrusions réseau</li></ul></details><h3 id="modeles-de-recommandation" tabindex="-1">Modèles de recommandation <a class="header-anchor" href="#modeles-de-recommandation" aria-label="Permalink to &quot;Modèles de recommandation&quot;">​</a></h3><p>👉 <em>« Qu’est-ce qui pourrait t’intéresser ? »</em></p><p>Proposer du contenu pertinent.</p><details class="details custom-block"><summary><strong>Exemples</strong></summary><ul><li>Netflix</li><li>Spotify</li><li>Amazon</li></ul></details><h3 id="modeles-de-reduction-de-dimension" tabindex="-1">Modèles de réduction de dimension <a class="header-anchor" href="#modeles-de-reduction-de-dimension" aria-label="Permalink to &quot;Modèles de réduction de dimension&quot;">​</a></h3><p>👉 <em>« Comment simplifier ? »</em></p><p>Réduire le nombre de variables tout en conservant l’essentiel.</p><details class="details custom-block"><summary><strong>Objectifs</strong></summary><ul><li>Visualisation</li><li>Accélération des modèles</li><li>Compression</li></ul></details><h3 id="modeles-de-series-temporelles" tabindex="-1">Modèles de séries temporelles <a class="header-anchor" href="#modeles-de-series-temporelles" aria-label="Permalink to &quot;Modèles de séries temporelles&quot;">​</a></h3><p>👉 <em>« Que va-t-il se passer ? »</em></p><p>Prédire le futur à partir du passé.</p><details class="details custom-block"><summary><strong>Exemples</strong></summary><ul><li>Prévisions de ventes</li><li>Charge serveur</li><li>Météo</li></ul></details><h3 id="apprentissage-par-renforcement" tabindex="-1">Apprentissage par renforcement <a class="header-anchor" href="#apprentissage-par-renforcement" aria-label="Permalink to &quot;Apprentissage par renforcement&quot;">​</a></h3><p>👉 <em>« Quelle action choisir ? »</em></p><p>Apprendre par <strong>essai-erreur</strong> à l’aide de récompenses.</p><details class="details custom-block"><summary><strong>Concepts clés</strong></summary><ul><li>Agent</li><li>Environnement</li><li>Récompense</li><li>Politique</li></ul></details><h3 id="modeles-de-generation" tabindex="-1">Modèles de génération <a class="header-anchor" href="#modeles-de-generation" aria-label="Permalink to &quot;Modèles de génération&quot;">​</a></h3><p>👉 <em>« Que puis-je créer ? »</em></p><p>Créer du <strong>nouveau contenu</strong>.</p><details class="details custom-block"><summary><strong>Exemples</strong></summary><ul><li>Texte</li><li>Images</li><li>Audio</li><li>Code</li></ul></details>',45)])])}const b=l(t,[["render",r]]);export{f as __pageData,b as default};
